import java.io.*;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        System.out.print("Enter your name: ");
        String userName = br.readLine();

        System.out.println("Hello, " + userName + "!");

        // Fixed code - encoding user input before including it in the output
        String encodedUserName = Encode.forHtml(userName);
        System.out.println("<script>alert('Hello, " + encodedUserName + "!')</script>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
